parts.content:
apiVersion: v1
data:
  default.conf.template: |
    server {
        listen 80;
        location / {
            proxy_pass ${REQUIRED_API_BASE};
        }
    }
kind: ConfigMap
metadata:
  labels:
    kustomize.toolkit.fluxcd.io/name: flux-system
    kustomize.toolkit.fluxcd.io/namespace: flux-system
  name: vigil-app-nginx-config
  namespace: default

parts.args:
{"title":"fix(remediation): set REQUIRED_API_BASE env in vigil-app Deployment","body":"Root cause: The REQUIRED_API_BASE environment variable is set to an empty string in the Deployment manifest, causing nginx envsubst to produce an invalid proxy_pass directive with no arguments

Evidence: 2026/06/06 23:40:52 [emerg] 1#1: invalid number of arguments in "proxy_pass" directive in /etc/nginx/conf.d/default.conf:4

Affected resources: Deployment/vigil-app, Pod/vigil-app-6895f8ff98-2gp8f"}
